import { useState, useEffect } from 'react';
import BankLogin from './components/BankLogin';
import PaymentConfirm from './components/PaymentConfirm';
import PaymentSuccess from './components/PaymentSuccess';
import './App.css';

function App() {
  const [currentPage, setCurrentPage] = useState('login');
  const [loggedInAccountId, setLoggedInAccountId] = useState(null);

  useEffect(() => {
    // Check if redirected from EIMS payment
    const params = new URLSearchParams(window.location.search);
    if (params.get('student_id') && params.get('amount')) {
      // Payment redirect from EIMS
      if (currentPage === 'login') {
        setCurrentPage('confirm');
      }
    }

    // Auto redirect to success after payment
    if (window.location.pathname.includes('payment-success')) {
      setCurrentPage('success');
    }
  }, []);

  const handleLoginSuccess = (accountId) => {
    setLoggedInAccountId(accountId);
    setCurrentPage('confirm');
  };

  const handlePaymentSuccess = () => {
    setCurrentPage('success');
    // Auto redirect after 3 seconds
    setTimeout(() => {
      window.location.href = 'http://localhost:3000/student/payment-success';
    }, 3000);
  };

  const handleBackToLogin = () => {
    setCurrentPage('login');
    setLoggedInAccountId(null);
  };

  return (
    <div className="app">
      {currentPage === 'login' && <BankLogin onLoginSuccess={handleLoginSuccess} />}
      {currentPage === 'confirm' && (
        <PaymentConfirm
          accountId={loggedInAccountId}
          onSuccess={handlePaymentSuccess}
          onBack={handleBackToLogin}
        />
      )}
      {currentPage === 'success' && <PaymentSuccess />}
    </div>
  );
}

export default App;
